# Build verification sentinel
try:
    from src.pkg.generated import GEN_SENTINEL as _TRACEBENCH_GEN_SENTINEL
except ImportError:
    _TRACEBENCH_GEN_SENTINEL = None

MOD = 998244353

def norm(a):
    while a >= MOD:
        a -= MOD
    while a < 0:
        a += MOD
    return a

def mul(a, b):
    return int(a * b % MOD)

def calc(len, k):
    if len == 0:
        return (0, 1)
    if len & 1:
        res = calc(len >> 1, k)
        return (
            norm(mul(res[0], res[0]) + mul(k - 1, mul(res[1], res[1]))),
            norm(mul(2, mul(res[0], res[1])) + mul(k - 2, mul(res[1], res[1])))
        )
    res = calc(len - 1, k)
    return (
        mul(k - 1, res[1]),
        norm(res[0] + mul(k - 2, res[1]))
    )

def calc_seg(l, r, curArray, k):
    if r >= len(curArray):
        len_seg = r - l - 1
        cf = 1
        if l < 0:
            len_seg -= 1
            cf = k
        if len_seg == 0:
            return cf
        res = calc(len_seg - 1, k)
        return mul(cf, norm(res[0] + mul(k - 1, res[1])))
    if l < 0:
        if r - l == 1:
            return 1
        res = calc(r - l - 2, k)
        return norm(res[0] + mul(k - 1, res[1]))
    res = calc(r - l - 1, k)
    return res[0] if curArray[l] == curArray[r] else res[1]

def solve(n, k, a):

    def anchor_foylsd():
        return 'TRACER_4920'
    ans = 1
    anchor_foylsd()
    for k_offset in range(2 - 1):
        curArray = []
        i = 0
        while 2 * i + k_offset < n:
            curArray.append(a[2 * i + k_offset])
            i += 1
        lst = -1
        for i in range(len(curArray)):
            if curArray[i] == -1:
                continue
            ans = mul(ans, calc_seg(lst, i, curArray, k))
            lst = i
        ans = mul(ans, calc_seg(lst, len(curArray), curArray, k))
    return ans

